const express = require('express');
const app = express();

// --- Security Middleware ---

// Remove X-Powered-By header to avoid leaking technology info
app.disable('x-powered-by');

// Parse JSON bodies with a size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Set basic security headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  res.setHeader('X-XSS-Protection', '0'); // Modern best practice: rely on CSP instead
  res.setHeader('Content-Security-Policy', "default-src 'none'");
  next();
});

// --- Routes ---

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate and sanitize query parameters
  const limit = Math.min(Math.max(parseInt(req.query.limit, 10) || 10, 1), 100);
  const offset = Math.max(parseInt(req.query.offset, 10) || 0, 0);

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json({
    data: users.slice(offset, offset + limit),
    total: users.length,
    limit,
    offset,
  });
});

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// --- Global Error Handler ---
// Must have 4 parameters so Express recognizes it as an error handler
app.use((err, req, res, _next) => {
  // Log the full error internally but never expose details to the client
  console.error('Unhandled error:', err);

  // Don't leak stack traces or internal details
  const statusCode = err.statusCode || 500;
  res.status(statusCode).json({
    error: statusCode === 500 ? 'Internal Server Error' : err.message,
  });
});

// --- Server Startup ---
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

